export function Logo({ size, ...iconProps }: IconProps & { size: number }) {
  const outerRingSize = size + 4;
  const innerRingSize = size + 2;
  const logoSize = size;

  const [outerRingVisible, setOuterRingVisible] = useState(false);
  const [innerRingVisible, setInnerRingVisible] = useState(false);

  const handleMouseEnter = () => {
    setInnerRingVisible(true);
    setTimeout(() => {
      setOuterRingVisible(true);
    }, 100); // Delay for the inner layer
  };

  const handleMouseLeave = () => {
    setOuterRingVisible(false);
    setTimeout(() => {
      setInnerRingVisible(false);
    }, 100);
  };

  return (
    <Flex
      h={outerRingSize}
      w={outerRingSize}
      background="linear-gradient(180deg, rgba(225, 124, 24, 0.4) 0%, rgba(204, 73, 0, 0.7) 100%)"
      borderRadius="xl"
      transition="visibility 0.1s ease"
      visibility={outerRingVisible ? 'visible' : 'hidden'}
      alignItems="center"
      justifyContent="center"
      className="logo-outer-ring"
    >
      <Flex
        h={innerRingSize}
        w={innerRingSize}
        background="linear-gradient(180deg, rgba(255, 152, 53, 0.7) 0%, rgba(252, 100, 50, 0.9) 100%)"
        borderRadius="xl"
        visibility={innerRingVisible ? 'visible' : 'hidden'}
        transition="visibility 0.1s ease"
        alignItems="center"
        justifyContent="center"
        className="logo-inner-ring"
      >
        <Flex
          bg="navbar.logo.bg"
          className="logo"
          h={logoSize}
          w={logoSize}
          borderRadius="xl"
          alignItems="center"
          justifyContent="center"
          visibility="visible"
          onMouseEnter={handleMouseEnter}
          onMouseLeave={handleMouseLeave}
        >
          <ExplorerLink href={'/'} title="Stacks Explorer">
            <Icon h={6} w={6} color="navbar.logo.icon" aria-label="Homepage" {...iconProps}>
              <StxIcon />
            </Icon>
          </ExplorerLink>
        </Flex>
      </Flex>
    </Flex>
  );
}
